import React from "react";


const Review = () => {
    return(
        <>
        <div className="container">
            <div className="header-container">
                <h1 className="heading">Powered by Leading Cloud-Native Companies</h1>
                <h6 className="heading1">Backed by Top Cloud-Native Enterprises</h6>
            </div>
        </div>
        </>
    )
}

export default Review;
